Step 3: Build the Event Server

// server.ts
import { serve } from 'bun';
import { Database } from 'bun:sqlite';
const db = new Database('events.db');
db.run(`
CREATE TABLE IF NOT EXISTS events (
id INTEGER PRIMARY KEY AUTOINCREMENT,
timestamp TEXT,
app_name TEXT,
session_id TEXT,
event_type TEXT,
data TEXT
)
`);
const clients = new Set<WebSocket>();
serve({
port: 3000,
async fetch(req, server) {
const url = new URL(req.url);
// Handle event ingestion
if (url.pathname === '/events' && req.method === 'POST') {
const event = await req.json();
// Store in database
db.run(
'INSERT INTO events (timestamp, app_name, session_id, event_type, data) VALUES (?, ?, ?, ?, ?)',
event.timestamp,
event.app_name,
event.session_id,
event.event_type,
JSON.stringify(event)
);
// Broadcast to all connected clients
const message = JSON.stringify({
type: 'event',
data: event
});
clients.forEach(client => {
if (client.readyState === WebSocket.OPEN) {
client.send(message);
}
});
return new Response('OK');
}
// Upgrade to WebSocket for real-time updates
if (url.pathname === '/ws') {
if (server.upgrade(req)) {
return;
}
}
return new Response('Not found', { status: 404 });
},
websocket: {
open(ws) {
clients.add(ws);
console.log('Client connected');
},
close(ws) {
clients.delete(ws);
console.log('Client disconnected');
},
message(ws, message) {
// Handle client messages if needed
}
}
});
console.log('Observability server running on http://localhost:3000');

